  'ib-bio-9-plant-biology': `<svg viewBox="0 0 400 300" xmlns="http://www.w3.org/2000/svg"><style>@keyframes plt_w{0%{transform:translateY(0)}50%{transform:translateY(-4px)}100%{transform:translateY(0)}}rect{fill:var(--surface)}.lbl{font-family:sans-serif;fill:var(--text);font-size:11px;font-weight:600}.sm{font-family:sans-serif;fill:var(--text-dim);font-size:9px}</style><rect width="400" height="300" rx="8"/><text x="200" y="22" text-anchor="middle" class="lbl" style="font-size:13px">Plant Biology</text><g transform="translate(18,35)"><text x="0" y="12" class="lbl">Stomatal Opening</text><ellipse cx="55" cy="60" rx="20" ry="10" fill="none" stroke="var(--accent)" stroke-width="2"/><ellipse cx="55" cy="60" rx="6" ry="6" fill="none" stroke="var(--text-dim)" stroke-width="1.5"/><text x="55" y="80" text-anchor="middle" class="sm">open</text><ellipse cx="130" cy="60" rx="20" ry="10" fill="none" stroke="var(--border)" stroke-width="2"/><ellipse cx="130" cy="60" rx="2" ry="3" fill="none" stroke="var(--text-dim)" stroke-width="1.5"/><text x="130" y="80" text-anchor="middle" class="sm">closed</text><text x="0" y="98" class="sm">Light → guard cells import K⁺ → osmosis</text><text x="0" y="110" class="sm">→ turgor ↑ → stoma opens</text></g><g transform="translate(18,130)"><text x="0" y="12" class="lbl">Transpiration Stream</text><rect x="60" y="20" width="10" height="80" rx="2" fill="none" stroke="var(--accent)" stroke-width="2"/><text x="75" y="60" class="sm">xylem</text><circle cx="65" cy="20" r="5" fill="var(--accent)" opacity=".7" style="animation:plt_w 2s infinite"/><circle cx="65" cy="35" r="5" fill="var(--accent)" opacity=".5"/><circle cx="65" cy="50" r="5" fill="var(--accent)" opacity=".4"/><text x="0" y="110" class="sm">Cohesion-tension: transpiration</text><text x="0" y="122" class="sm">at leaf creates −ve pressure</text></g><g transform="translate(200,35)"><text x="0" y="12" class="lbl">Auxin and Tropisms</text><rect x="0" y="20" width="180" height="60" rx="4" fill="var(--accent)" opacity=".1"/><text x="90" y="38" text-anchor="middle" class="sm">Phototropism: auxin migrates to shaded</text><text x="90" y="50" text-anchor="middle" class="sm">side → elongation → bends toward light</text><text x="90" y="64" text-anchor="middle" class="sm">Gravitropism: root tip grows downward</text><text x="0" y="98" class="lbl">Phloem — Pressure Flow</text><text x="0" y="112" class="sm">Source (leaf): sucrose loaded → low Ψ</text><text x="0" y="124" class="sm">→ water enters → ↑ pressure</text><text x="0" y="138" class="sm">Sink (root): sucrose unloaded → ↓ pressure</text><text x="0" y="152" class="sm">Mass flow drives sucrose source → sink</text></g></svg>`,

