  // IB BIO 11: Animal Physiology
  'ib-bio-11-animal-physiology': `<svg viewBox="0 0 400 300" width="100%" height="100%" xmlns="http://www.w3.org/2000/svg"><rect width="400" height="300" fill="#f4f6f7"/><path d="M200 80 C150 80, 120 130, 150 200 C170 240, 200 270, 200 270 C200 270, 230 240, 250 200 C280 130, 250 80, 200 80 Z" fill="#e74c3c" stroke="#c0392b" stroke-width="4"/><path d="M200 100 L200 260" stroke="#c0392b" stroke-width="15"/><line x1="140" y1="160" x2="200" y2="160" stroke="#ecf0f1" stroke-width="4" stroke-dasharray="5,5"/><line x1="200" y1="160" x2="260" y2="160" stroke="#ecf0f1" stroke-width="4" stroke-dasharray="5,5"/><path d="M210 100 C210 50, 260 40, 260 80" fill="none" stroke="#e74c3c" stroke-width="12"/><path d="M190 100 C190 50, 140 40, 140 80" fill="none" stroke="#3498db" stroke-width="12"/><path d="M150 120 L130 60" stroke="#3498db" stroke-width="10"/><polygon points="140,110 145,120 135,120" fill="#2c3e50"/><polygon points="260,110 265,120 255,120" fill="#2c3e50"/><text x="140" y="140" font-family="Arial" font-size="12" fill="#fff" font-weight="bold">RA</text><text x="240" y="140" font-family="Arial" font-size="12" fill="#fff" font-weight="bold">LA</text><text x="150" y="220" font-family="Arial" font-size="14" fill="#fff" font-weight="bold">RV</text><text x="230" y="220" font-family="Arial" font-size="14" fill="#fff" font-weight="bold">LV</text><text x="275" y="60" font-family="Arial" font-size="12" fill="#c0392b">Aorta</text><circle cx="-10" cy="-10" r="1" opacity="0"/><circle cx="-10" cy="-10" r="1" opacity="0"/></svg>`,

