  // IB BIO 17: Microbiomes
  'ib-bio-microbiomes': `<svg viewBox="0 0 400 300" xmlns="http://www.w3.org/2000/svg"><style>@keyframes mic_r{0%{transform:rotate(0deg)}100%{transform:rotate(360deg)}}rect{fill:var(--surface)}.lbl{font-family:sans-serif;fill:var(--text);font-size:11px;font-weight:600}.sm{font-family:sans-serif;fill:var(--text-dim);font-size:9px}</style><rect width="400" height="300" rx="8"/><text x="200" y="22" text-anchor="middle" class="lbl" style="font-size:13px">Microbiomes</text><g transform="translate(18,35)"><text x="0" y="12" class="lbl">Gut Microbiome</text><circle cx="70" cy="80" r="50" fill="none" stroke="var(--accent)" stroke-width="2"/><circle cx="70" cy="80" r="3" fill="var(--accent)" opacity=".8"/><circle cx="85" cy="55" r="2" fill="var(--accent)" opacity=".6"/><circle cx="50" cy="65" r="2" fill="var(--accent)" opacity=".7"/><circle cx="90" cy="95" r="2.5" fill="var(--accent)" opacity=".5"/><circle cx="55" cy="100" r="2" fill="var(--accent)" opacity=".6"/><circle cx="40" cy="80" r="1.5" fill="var(--accent)" opacity=".4"/><text x="70" y="145" text-anchor="middle" class="sm">~1000+ bacterial species</text></g><g transform="translate(150,35)"><text x="0" y="12" class="lbl">Functions</text><rect x="0" y="20" width="220" height="18" rx="3" fill="var(--accent)" opacity=".2"/><text x="110" y="33" text-anchor="middle" class="sm">1. Fibre fermentation → short-chain fatty acids</text><rect x="0" y="42" width="220" height="18" rx="3" fill="var(--accent)" opacity=".15"/><text x="110" y="55" text-anchor="middle" class="sm">2. Vitamin synthesis (B12, K, folate)</text><rect x="0" y="64" width="220" height="18" rx="3" fill="var(--accent)" opacity=".2"/><text x="110" y="77" text-anchor="middle" class="sm">3. Immune system training</text><rect x="0" y="86" width="220" height="18" rx="3" fill="var(--accent)" opacity=".15"/><text x="110" y="99" text-anchor="middle" class="sm">4. Pathogen resistance (colonisation resistance)</text></g><g transform="translate(150,150)"><text x="0" y="12" class="lbl">Metagenomics</text><text x="0" y="26" class="sm">Extract total DNA from sample</text><text x="0" y="40" class="sm">NGS → millions of sequence reads</text><text x="0" y="54" class="sm">Bioinformatics → identify organisms</text><text x="0" y="68" class="sm">No culturing needed (~99% unculturable)</text></g><g transform="translate(18,220)"><text x="0" y="12" class="lbl">Dysbiosis</text><text x="0" y="26" class="sm">Imbalance in microbiome community</text><text x="0" y="40" class="sm">Linked to IBD, obesity, autism, allergies</text><text x="0" y="54" class="sm">Antibiotics disturb → C. diff overgrowth</text></g></svg>`,

  // IB BIO 18: Climate Change and Ecosystems
