  // IB BIO 26: Hardy-Weinberg Principle
  'ib-bio-hardy-weinberg': `<svg viewBox="0 0 400 300" width="100%" height="100%" xmlns="http://www.w3.org/2000/svg"><rect width="400" height="300" fill="#f8f9fa"/><line x1="50" y1="250" x2="350" y2="250" stroke="#333" stroke-width="2"/><line x1="50" y1="50" x2="50" y2="250" stroke="#333" stroke-width="2"/><line x1="50" y1="150" x2="350" y2="150" stroke="#ccc" stroke-dasharray="4"/><line x1="50" y1="50" x2="350" y2="50" stroke="#ccc" stroke-dasharray="4"/><path d="M 50 250 Q 150 250 350 50" fill="none" stroke="#e74c3c" stroke-width="3"/><path d="M 350 250 Q 250 250 50 50" fill="none" stroke="#3498db" stroke-width="3"/><path d="M 50 250 Q 200 0 350 250" fill="none" stroke="#2ecc71" stroke-width="3"/><circle cx="200" cy="150" r="4" fill="#2ecc71"/><circle cx="137" cy="200" r="4" fill="#e74c3c"/><circle cx="263" cy="200" r="4" fill="#3498db"/><circle cx="200" cy="250" r="4" fill="#333"/><rect x="250" y="70" width="12" height="12" fill="#e74c3c"/><rect x="250" y="90" width="12" height="12" fill="#2ecc71"/><rect x="250" y="110" width="12" height="12" fill="#3498db"/><text x="270" y="80" font-family="sans-serif" font-size="12">p² (Homozygous Dominant)</text><text x="270" y="100" font-family="sans-serif" font-size="12">2pq (Heterozygous)</text><text x="270" y="120" font-family="sans-serif" font-size="12">q² (Homozygous Recessive)</text><text x="200" y="280" font-family="sans-serif" font-size="14" text-anchor="middle">Allele Frequency (p)</text><text x="30" y="155" font-family="sans-serif" font-size="12">0.5</text><text x="30" y="55" font-family="sans-serif" font-size="12">1.0</text></svg>`,

