  // IB PHYS 4: Waves
  'ib-phys-4-waves': `<svg viewBox="0 0 400 300" xmlns="http://www.w3.org/2000/svg"><style>@keyframes wv_t{0%{transform:translateX(0)}100%{transform:translateX(-40px)}}rect{fill:var(--surface)}.lbl{font-family:sans-serif;fill:var(--text);font-size:11px;font-weight:600}.sm{font-family:sans-serif;fill:var(--text-dim);font-size:9px}.val{font-family:sans-serif;fill:var(--text);font-size:10px;font-weight:700}</style><rect width="400" height="300" rx="8"/><text x="200" y="20" text-anchor="middle" class="lbl" style="font-size:13px">Waves</text><text x="96" y="36" text-anchor="middle" class="lbl">Transverse Wave</text><line x1="10" y1="65" x2="190" y2="65" stroke="var(--text-dim)" stroke-width="1"/><path d="M10,65 C30,65 35,35 55,35 C75,35 80,95 100,95 C120,95 125,35 145,35 C165,35 170,95 190,95" fill="none" stroke="var(--accent)" stroke-width="2" style="animation:wv_t 1s linear infinite"/><line x1="55" y1="35" x2="55" y2="65" stroke="var(--text-dim)" stroke-width="1" stroke-dasharray="2,2"/><text x="55" y="30" text-anchor="middle" class="sm" style="fill:var(--accent)">A</text><line x1="55" y1="35" x2="145" y2="35" stroke="var(--text-dim)" stroke-width="1" stroke-dasharray="2,2"/><text x="100" y="30" text-anchor="middle" class="sm">λ</text><text x="8" y="106" class="sm">Longitudinal: compression &amp; rarefaction (e.g. sound)</text><line x1="10" y1="120" x2="185" y2="120" stroke="var(--text-dim)" stroke-width="1"/><rect x="14" y="112" width="12" height="16" fill="var(--accent)" opacity=".8"/><rect x="34" y="115" width="6" height="10" fill="var(--accent)" opacity=".4"/><rect x="48" y="112" width="12" height="16" fill="var(--accent)" opacity=".8"/><rect x="68" y="115" width="6" height="10" fill="var(--accent)" opacity=".4"/><rect x="82" y="112" width="12" height="16" fill="var(--accent)" opacity=".8"/><rect x="102" y="115" width="6" height="10" fill="var(--accent)" opacity=".4"/><rect x="116" y="112" width="12" height="16" fill="var(--accent)" opacity=".8"/><rect x="136" y="115" width="6" height="10" fill="var(--accent)" opacity=".4"/><rect x="150" y="112" width="12" height="16" fill="var(--accent)" opacity=".8"/><text x="96" y="140" text-anchor="middle" class="sm">C = compression, R = rarefaction</text><text x="205" y="36" class="lbl">Wave Equations</text><rect x="200" y="40" width="193" height="20" rx="4" fill="var(--accent)" opacity=".2"/><text x="296" y="54" text-anchor="middle" class="val">v = fλ  |  T = 1/f</text><text x="205" y="74" class="sm">Amplitude A: max displacement</text><text x="205" y="86" class="sm">Period T: time per cycle (s)</text><text x="205" y="98" class="sm">Frequency f: cycles per second (Hz)</text><text x="205" y="114" class="lbl">Wave Behaviour</text><text x="205" y="126" class="sm">Reflection: angle in = angle out</text><text x="205" y="138" class="sm">Refraction: speed change → bending</text><text x="205" y="150" class="sm">n = sin θ₁/sin θ₂ = v₁/v₂</text><text x="205" y="166" class="lbl">Doppler Effect</text><text x="205" y="178" class="sm">Source → observer: f′ = f(v/(v−vs))</text><text x="205" y="190" class="sm">Source away: f′ = f(v/(v+vs))</text><text x="205" y="206" class="lbl">Electromagnetic Spectrum</text><text x="205" y="218" class="sm">γ, X, UV, visible, IR, micro, radio</text><text x="205" y="230" class="sm">All travel at c = 3×10⁸ m s⁻¹ in vacuum</text><text x="205" y="246" class="lbl">Polarisation</text><text x="205" y="258" class="sm">Transverse only; by filter, reflection</text><text x="205" y="270" class="sm">Malus's law: I = I₀cos²θ</text><text x="205" y="286" class="sm">Brewster's angle: tan θB = n</text></svg>`,

