  // IB PHYS 7: Atomic, Nuclear & Particle Physics
  'ib-phys-7-atomic-nuclear': `<svg viewBox="0 0 400 300" xmlns="http://www.w3.org/2000/svg"><style>@keyframes an_d{0%{opacity:1;transform:translate(0,0)}100%{opacity:0;transform:translate(30px,-20px)}}rect{fill:var(--surface)}.lbl{font-family:sans-serif;fill:var(--text);font-size:11px;font-weight:600}.sm{font-family:sans-serif;fill:var(--text-dim);font-size:9px}.val{font-family:sans-serif;fill:var(--text);font-size:10px;font-weight:700}</style><rect width="400" height="300" rx="8"/><text x="200" y="20" text-anchor="middle" class="lbl" style="font-size:13px">Atomic, Nuclear &amp; Particle</text><circle cx="80" cy="95" r="18" fill="var(--accent)" opacity=".3"/><text x="80" y="99" text-anchor="middle" class="sm" style="font-weight:700">nucleus</text><circle cx="80" cy="95" r="40" fill="none" stroke="var(--text-dim)" stroke-width="1" stroke-dasharray="3,3"/><circle cx="80" cy="55" r="4" fill="var(--accent)"/><circle cx="80" cy="95" r="40" fill="none" stroke="var(--text-dim)" stroke-width="0.5" opacity=".4"/><circle cx="120" cy="95" r="4" fill="var(--accent)"/><circle cx="80" cy="135" r="4" fill="var(--accent)"/><circle cx="40" cy="95" r="4" fill="var(--accent)"/><text x="80" y="148" text-anchor="middle" class="sm">Bohr model: quantised orbits</text><circle cx="150" cy="90" r="6" fill="var(--accent)" opacity=".8" style="animation:an_d 3s infinite ease-out"/><text x="162" y="87" class="sm" style="fill:var(--accent)">α</text><text x="205" y="36" class="lbl">Radioactive Decay</text><text x="205" y="50" class="sm">α: ₂⁴He emitted; A−4, Z−2</text><text x="205" y="62" class="sm">β⁻: neutron→proton+e⁻+ν̄e; Z+1</text><text x="205" y="74" class="sm">β⁺: proton→neutron+e⁺+νe; Z−1</text><text x="205" y="86" class="sm">γ: high-energy photon; A,Z unchanged</text><text x="205" y="102" class="lbl">Half-life &amp; Decay Law</text><rect x="200" y="106" width="193" height="20" rx="4" fill="var(--accent)" opacity=".2"/><text x="296" y="120" text-anchor="middle" class="val">N = N₀e^(−λt)  t½ = ln2/λ</text><text x="205" y="140" class="sm">A = λN (activity in Bq)</text><text x="205" y="156" class="lbl">Standard Model</text><text x="205" y="168" class="sm">Quarks: up(+⅔), down(−⅓) — 6 flavours</text><text x="205" y="180" class="sm">Proton: uud | Neutron: udd</text><text x="205" y="192" class="sm">Leptons: e, μ, τ &amp; neutrinos</text><text x="205" y="208" class="lbl">Fundamental Forces</text><text x="205" y="220" class="sm">Strong: gluons, binds quarks in nucleus</text><text x="205" y="232" class="sm">Weak: W/Z bosons, β decay</text><text x="205" y="244" class="sm">EM: photons | Gravity: gravitons (unconfirmed)</text><text x="205" y="260" class="lbl">Photoelectric Effect</text><text x="205" y="272" class="sm">hf = φ + ½mv²max (photon energy)</text><text x="205" y="284" class="sm">φ: work function; threshold: f₀ = φ/h</text></svg>`,

