  // IB PHYS 12: Fields (HL)
  'ib-phys-10-fields': `<svg viewBox="0 0 400 300" xmlns="http://www.w3.org/2000/svg"><style>@keyframes fl_p{0%{opacity:.2}100%{opacity:1}}rect{fill:var(--surface)}.lbl{font-family:sans-serif;fill:var(--text);font-size:11px;font-weight:600}.sm{font-family:sans-serif;fill:var(--text-dim);font-size:9px}.val{font-family:sans-serif;fill:var(--text);font-size:10px;font-weight:700}</style><rect width="400" height="300" rx="8"/><text x="200" y="20" text-anchor="middle" class="lbl" style="font-size:13px">Fields (HL)</text><text x="50" y="36" text-anchor="middle" class="lbl">Gravitational</text><circle cx="50" cy="95" r="10" fill="var(--text-dim)" opacity=".6"/><text x="50" y="99" text-anchor="middle" class="sm" style="fill:var(--text)">M</text><path d="M60,85 L80,70" fill="none" stroke="var(--text-dim)" stroke-width="1" marker-end="url(#a)" style="animation:fl_p 2s infinite"/><path d="M62,95 L84,95" fill="none" stroke="var(--text-dim)" stroke-width="1" style="animation:fl_p 2s infinite"/><path d="M60,105 L80,120" fill="none" stroke="var(--text-dim)" stroke-width="1" style="animation:fl_p 2s infinite"/><path d="M50,105 L50,127" fill="none" stroke="var(--text-dim)" stroke-width="1" style="animation:fl_p 2s infinite"/><path d="M40,105 L20,120" fill="none" stroke="var(--text-dim)" stroke-width="1" style="animation:fl_p 2s infinite"/><path d="M38,95 L16,95" fill="none" stroke="var(--text-dim)" stroke-width="1" style="animation:fl_p 2s infinite"/><text x="50" y="145" text-anchor="middle" class="sm">Radial, toward mass</text><text x="150" y="36" text-anchor="middle" class="lbl">Electric</text><circle cx="150" cy="95" r="10" fill="var(--accent)" opacity=".8"/><text x="150" y="99" text-anchor="middle" class="sm" style="fill:white">+</text><path d="M162,88 L182,73" fill="none" stroke="var(--accent)" stroke-width="1" style="animation:fl_p 2s infinite"/><path d="M162,95 L185,95" fill="none" stroke="var(--accent)" stroke-width="1" style="animation:fl_p 2s infinite"/><path d="M162,102 L182,117" fill="none" stroke="var(--accent)" stroke-width="1" style="animation:fl_p 2s infinite"/><path d="M150,105 L150,127" fill="none" stroke="var(--accent)" stroke-width="1" style="animation:fl_p 2s infinite"/><path d="M138,102 L118,117" fill="none" stroke="var(--accent)" stroke-width="1" style="animation:fl_p 2s infinite"/><path d="M138,95 L115,95" fill="none" stroke="var(--accent)" stroke-width="1" style="animation:fl_p 2s infinite"/><text x="150" y="145" text-anchor="middle" class="sm">Radial, away from +</text><text x="205" y="36" class="lbl">Gravitational Field</text><text x="205" y="50" class="sm">g = GM/r² (field strength, N kg⁻¹)</text><text x="205" y="62" class="sm">V_g = −GM/r (potential, J kg⁻¹)</text><text x="205" y="74" class="sm">g = −dV_g/dr</text><text x="205" y="86" class="sm">Equipotentials ⊥ field lines</text><text x="205" y="102" class="lbl">Electric Field</text><text x="205" y="114" class="sm">E = kQ/r² = F/q (N C⁻¹ or V m⁻¹)</text><text x="205" y="126" class="sm">V_E = kQ/r (potential, J C⁻¹ = V)</text><text x="205" y="138" class="sm">E = −dV/dx (uniform: E = V/d)</text><text x="205" y="154" class="lbl">Comparison Table</text><rect x="200" y="158" width="193" height="13" rx="2" fill="var(--accent)" opacity=".25"/><text x="205" y="168" class="sm" style="font-weight:700">Property  Grav.     Electric</text><text x="205" y="180" class="sm">Force law  GMm/r²   kQq/r²</text><text x="205" y="192" class="sm">Field      GM/r²     kQ/r²</text><text x="205" y="204" class="sm">Potential  −GM/r     kQ/r</text><text x="205" y="216" class="sm">Always?    Attractive  ±</text><text x="205" y="232" class="lbl">Potential Energy</text><text x="205" y="244" class="sm">W = qΔV (electric); W = mΔV_g (grav.)</text><text x="205" y="256" class="sm">ΔKE = −ΔPE (conservative field)</text><text x="205" y="272" class="lbl">Orbital Energy</text><text x="205" y="284" class="sm">E_total = KE + PE = −GMm/2r</text></svg>`,

  // IB PHYS 13: Wave Interference (HL)
  'ib-phys-wave-interference': `<svg viewBox="0 0 400 300" xmlns="http://www.w3.org/2000/svg"><style>@keyframes wi_r{0%{r:5}100%{r:80}}rect{fill:var(--surface)}.lbl{font-family:sans-serif;fill:var(--text);font-size:11px;font-weight:600}.sm{font-family:sans-serif;fill:var(--text-dim);font-size:9px}.val{font-family:sans-serif;fill:var(--text);font-size:10px;font-weight:700}</style><rect width="400" height="300" rx="8"/><text x="200" y="20" text-anchor="middle" class="lbl" style="font-size:13px">Wave Interference</text><text x="96" y="36" text-anchor="middle" class="lbl">Double Slit (Young's)</text><rect x="85" y="38" width="6" height="35" fill="var(--text-dim)"/><rect x="85" y="83" width="6" height="14" fill="none"/><rect x="85" y="97" width="6" height="14" fill="none"/><rect x="85" y="111" width="6" height="37" fill="var(--text-dim)"/><circle cx="88" cy="90" r="2" fill="var(--accent)"/><circle cx="88" cy="108" r="2" fill="var(--accent)"/><circle cx="88" cy="90" r="18" fill="none" stroke="var(--accent)" stroke-width="1" opacity=".5"/><circle cx="88" cy="90" r="36" fill="none" stroke="var(--accent)" stroke-width="1" opacity=".4"/><circle cx="88" cy="108" r="18" fill="none" stroke="var(--accent)" stroke-width="1" opacity=".5"/><circle cx="88" cy="108" r="36" fill="none" stroke="var(--accent)" stroke-width="1" opacity=".4"/><line x1="160" y1="40" x2="160" y2="165" stroke="var(--text-dim)" stroke-width="1"/><rect x="158" y="91" width="4" height="16" fill="var(--accent)" opacity=".9"/><rect x="158" y="70" width="4" height="10" fill="var(--accent)" opacity=".5"/><rect x="158" y="113" width="4" height="10" fill="var(--accent)" opacity=".5"/><rect x="158" y="55" width="4" height="6" fill="var(--accent)" opacity=".25"/><rect x="158" y="130" width="4" height="6" fill="var(--accent)" opacity=".25"/><text x="96" y="180" text-anchor="middle" class="sm">Bright fringes (constructive) on screen</text><text x="205" y="36" class="lbl">Young's Experiment</text><rect x="200" y="40" width="193" height="20" rx="4" fill="var(--accent)" opacity=".2"/><text x="296" y="54" text-anchor="middle" class="val">y = mλD/d</text><text x="205" y="74" class="sm">y: fringe spacing; D: slit-screen dist.</text><text x="205" y="86" class="sm">d: slit separation; m: order (0,1,2...)</text><text x="205" y="102" class="lbl">Path Difference Conditions</text><text x="205" y="114" class="sm">Constructive: Δ = mλ (bright)</text><text x="205" y="126" class="sm">Destructive: Δ = (m+½)λ (dark)</text><text x="205" y="142" class="lbl">Intensity Pattern</text><text x="205" y="154" class="sm">I ∝ cos²(δ/2) (two sources)</text><text x="205" y="166" class="sm">Envelope: single-slit diffraction</text><text x="205" y="182" class="lbl">Thin Film Interference</text><text x="205" y="194" class="sm">Path diff = 2nt (n = refractive index)</text><text x="205" y="206" class="sm">Phase change on reflection at denser medium</text><text x="205" y="222" class="lbl">Coherence</text><text x="205" y="234" class="sm">Sources must be coherent (fixed Δφ)</text><text x="205" y="246" class="sm">Same frequency, constant phase relation</text><text x="205" y="262" class="lbl">Michelson Interferometer</text><text x="205" y="274" class="sm">Splits &amp; recombines beams; measures λ</text></svg>`,

